import boto3
import json

def lambda_handler(event, context):
    s3 = boto3.client('s3')
    sns = boto3.client('sns')

    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    # Read image from S3
    response = s3.get_object(Bucket=bucket_name, Key=object_key)
    image_data = response['Body'].read()

    # Process the image (example: convert to grayscale)
    processed_image_data = process_image(image_data)

    # Write results back to S3
    output_bucket_name = 'output-bucket-name'
    output_object_key = f'processed_{object_key}'
    s3.put_object(Bucket=output_bucket_name, Key=output_object_key, Body=processed_image_data)

    # Send notification via SNS
    sns.publish(
        TopicArn='arn:aws:sns:us-east-1:123456789012:my-topic',
        Message=json.dumps({'default': 'Image processed successfully'}),
        Subject='Image Processing Notification'
    )

    # Log to CloudWatch
    logger = boto3.client('logs')
    log_group_name = '/aws/lambda/my-lambda-function'
    log_stream_name = context.log_stream_name
    log_message = f'Processed image {object_key}'
    logger.put_log_events(
        logGroupName=log_group_name,
        logStreamName=log_stream_name,
        logEvents=[{'timestamp': int(context.aws_request_id), 'message': log_message}]
    )

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed and saved successfully')
    }

